67:    `define CHECK_TYPE_CFG  (dcom.com_dout[9:8] == 2'b01)
68:    `define CHECK_TYPE_LOOP (dcom.com_dout[9:8] == 2'b10)
69:    `define CHECK_TYPE_CMD  (dcom.com_dout[9:8] == 2'b11)
71:    assign   dtlp.tx_valid = dcom.com_dout_valid & `CHECK_MAGIC & `CHECK_TYPE_TLP;
72:    assign   dcfg.tx_valid = dcom.com_dout_valid & `CHECK_MAGIC & `CHECK_TYPE_CFG;
73:    wire     _loop_rx_wren = dcom.com_dout_valid & `CHECK_MAGIC & `CHECK_TYPE_LOOP;
74:    wire     _cmd_rx_wren  = dcom.com_dout_valid & `CHECK_MAGIC & `CHECK_TYPE_CMD;
77:    assign dtlp.tx_data = dcom.com_dout[63:32];
78:    assign dtlp.tx_last = dcom.com_dout[10];
113:        .din            ( {dcom.com_dout[11:10], dcom.com_dout[63:32]} ),
