263:            // MAGIC
264:            rw[15:0]    <= 16'hefcd;                    // +000: MAGIC
346:    wire [15:0] in_cmd_address_byte = cmd_rx_dout[31:16];
347:    wire [17:0] in_cmd_address_bit  = {in_cmd_address_byte[14:0], 3'b000};
350:    wire        f_rw                = in_cmd_address_byte[15];
351:    wire        f_shadowcfgspace    = in_cmd_address_byte[14];
